import{_ as r}from"./chunks/chooseRx.dmJ4OLlk.js";import{_ as t,c as a,o,ag as s}from"./chunks/framework.DRADY2L-.js";const g=JSON.parse(`{"title":"Beginner's Kit","description":"Which starting set to choose, how to start the FPV hobby, what are KIT/BNF, why \\"Cetus\\" might not be the best choice, options for various budgets, and much m...","frontmatter":{"description":"Which starting set to choose, how to start the FPV hobby, what are KIT/BNF, why \\"Cetus\\" might not be the best choice, options for various budgets, and much m...","gitAuthors":["mituritsyn","ikherty","Valentina Petrenko"]},"headers":[],"relativePath":"shop/set.md","filePath":"en/shop/set.md","lastUpdated":1771019108000}`),n={name:"shop/set.md"};function i(l,e,h,c,u,d){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="beginner-s-kit" tabindex="-1">Beginner&#39;s Kit <a class="header-anchor" href="#beginner-s-kit" aria-label="Permalink to &quot;Beginner&#39;s Kit&quot;">​</a></h1><p>Which starting set to choose, how to start the FPV hobby, what are KIT/BNF, why &quot;Cetus&quot; might not be the best choice, options for various budgets, and much more can be found below.</p><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>This article provides &quot;build it yourself&quot; set options with ready-made drones for specific budgets. <strong>Before exploring these options, please study the articles in the &quot;Introduction&quot; section (see the menu on the left)</strong>.</p><p>Since prices are originally in USD, the cost in other currencies will depend on the current exchange rate. Keep in mind that different platforms may have their own rates, and local stores may apply additional markups. Currency Converter: <a href="https://g.co/kgs/zsYNPm" target="_blank" rel="noreferrer">Google Finance</a>.</p><p>You can also build a drone yourself, but including consumables and tools, it will likely cost more. <a href="https://propwashservice.com/en/shop/DIY" target="_blank" rel="noreferrer">Example components for builds</a> and <a href="https://propwashservice.com/en/shop/nessesary" target="_blank" rel="noreferrer">Equipment and consumables list</a>.</p><p><strong>Please note that any set must primarily include a simulator.</strong></p><ul><li><a href="https://propwashservice.com/en/intro/sim" target="_blank" rel="noreferrer">Simulator examples</a></li></ul><h2 id="what-are-kit-rtf-pnp-bnf" tabindex="-1">What are KIT, RTF, PNP, BNF... <a class="header-anchor" href="#what-are-kit-rtf-pnp-bnf" aria-label="Permalink to &quot;What are KIT, RTF, PNP, BNF...&quot;">​</a></h2><p>In product names, you&#39;ll often see RTF, BNF, PNP, and ARF (KIT). These abbreviations specify the product&#39;s completeness.</p><h3 id="rtf-—-ready-to-fly" tabindex="-1">RTF — &quot;Ready to Fly&quot; <a class="header-anchor" href="#rtf-—-ready-to-fly" aria-label="Permalink to &quot;RTF — &quot;Ready to Fly&quot;&quot;">​</a></h3><p>Also sometimes called a &quot;Starter Kit&quot;.</p><p><strong>An RTF drone kit includes:</strong></p><ul><li>A drone with a receiver compatible with the included radio;</li><li>A radio controller;</li><li>A battery (or several);</li><li>A charger for the included battery.</li></ul><p>Typically, these kits consist of the cheapest possible parts. They are often given as gifts or bought by beginners. Most hobbyists <strong>strongly recommend against</strong> starting with these, as you&#39;ll likely have to buy everything from scratch if you want to expand your fleet, leaving the old kit useless. Over time, better RTF kits are appearing on the market. It is recommended to consult with experienced hobbyists about the current relevance of a chosen set before buying.</p><h3 id="bnf-—-bind-and-fly" tabindex="-1">BNF — &quot;Bind and Fly&quot; <a class="header-anchor" href="#bnf-—-bind-and-fly" aria-label="Permalink to &quot;BNF — &quot;Bind and Fly&quot;&quot;">​</a></h3><blockquote><p>What &quot;bind&quot; means can be found <a href="https://propwashservice.com/en/community/glossarium" target="_blank" rel="noreferrer">here</a>.</p></blockquote><p><strong>A BNF drone kit includes:</strong></p><ul><li>A drone with a pre-soldered receiver;</li><li>(Optional) A battery and corresponding charger, common for tiny whoops.</li></ul><p>Since different radio control systems are <strong>not compatible</strong> with each other (read about <a href="https://propwashservice.com/en/intro/tx#data-transmission-protocols" target="_blank" rel="noreferrer">current systems here</a>), buyers are often offered a choice of receiver. If no choice is given, the receiver name is usually in the BNF set title or description. You may also be offered a choice of camera (common for DJI FPV drones with Caddx Vista/Air Unit) and motor/propeller groups (specified by battery cell count, e.g., 4S or 6S).</p><p align="center"><img src="'+r+'" width="600" alt="example of drone variations with receivers"></p><p>After purchasing such a kit, you&#39;ll need to update the receiver firmware and bind it with your radio. For digital video systems, you&#39;ll also need to update its firmware and bind it with your goggles. In the flight controller firmware settings (usually Betaflight; check product description), you must set the correct channel mapping (<a href="https://oscarliang.com/channel-map/" target="_blank" rel="noreferrer">more details</a>) and configure modes for your switches (<a href="https://oscarliang.com/betaflight-modes/" target="_blank" rel="noreferrer">more details</a>).</p><h3 id="pnp-—-plug-and-play" tabindex="-1">PNP — &quot;Plug and Play&quot; <a class="header-anchor" href="#pnp-—-plug-and-play" aria-label="Permalink to &quot;PNP — &quot;Plug and Play&quot;&quot;">​</a></h3><p><strong>A PNP drone kit includes:</strong></p><ul><li>A drone without a receiver.</li></ul><p>As you might have guessed, you&#39;ll first need to buy a receiver, solder it in, and then follow the same steps as for a BNF kit.</p><h3 id="arf-kit-sets-—-almost-ready-to-fly" tabindex="-1">ARF (KIT sets) — &quot;Almost Ready to Fly&quot; <a class="header-anchor" href="#arf-kit-sets-—-almost-ready-to-fly" aria-label="Permalink to &quot;ARF (KIT sets) — &quot;Almost Ready to Fly&quot;&quot;">​</a></h3><p>ARF kits imply a set of all parts necessary for assembly. Modern ARF kits are rare and often sold by large bloggers or major brands. On AliExpress, you often find outdated versions that are not recommended without consulting hobbyists. For airplanes, a &quot;KIT&quot; set often means just the airframe without any electronics. Always check the description carefully.</p><h2 id="why-shouldn-t-you-buy-a-cetus" tabindex="-1">Why shouldn&#39;t you buy a &quot;Cetus&quot;? <a class="header-anchor" href="#why-shouldn-t-you-buy-a-cetus" aria-label="Permalink to &quot;Why shouldn&#39;t you buy a &quot;Cetus&quot;?&quot;">​</a></h2><p>BetaFPV was one of the first to release an RTF starter kit, and initially, the idea seemed great—buy and fly without worrying about missing parts. GEP-RC, EMAX, and Eachine followed with their own interpretations. However, these are often built so cheaply that the equipment quality is only good for &quot;feeling out&quot; the hobby, not for long-term use. Many hobbyists who receive or buy these eventually sell or discard them because the quality and functionality aren&#39;t enough for full immersion.</p><p>BetaFPV&#39;s line grew into the <a href="https://betafpv.com/collections/best-fpv-kits" target="_blank" rel="noreferrer">Cetus series</a>. They come in various versions, but they all share a common problem: BetaFPV&#39;s inconsistent quality. Despite their experience, they often struggle with reliable electronics, frequent small manufacturing defects, and poor soldering. A major issue is components &quot;popping off&quot; boards during crashes, requiring professional repair or replacement. Their goggles often have basic internals with poor receiver sensitivity. Their radios use a fork of EdgeTX rather than being integrated into the main project, and they are slow to update features. In their ELRS products, they sometimes ignore developer recommendations, resulting in worse performance than more affordable alternatives like Happymodel.</p><p>Of course, if you already have one, feel free to fly it and see if you enjoy the hobby. &quot;A bad experience is still an experience.&quot; You might get lucky and get a defect-free unit that teaches you the basics. But statistics generally suggest otherwise.</p><h2 id="i-want-to-start-but-have-no-money-50-200" tabindex="-1">I want to start, but have no money ($50-200) <a class="header-anchor" href="#i-want-to-start-but-have-no-money-50-200" aria-label="Permalink to &quot;I want to start, but have no money ($50-200)&quot;">​</a></h2><p>Unfortunately, it&#39;s very difficult to fully enter the hobby with this budget. Your best bet is an EdgeTX radio with USB charging capability, batteries for the radio, and a simulator. You won&#39;t be able to fly a real drone initially, but you&#39;ll get a feel for the controls and decide how interested you are. You can also participate in online races; with good results, you might join a racing team, find sponsors, and move up the &quot;career ladder.&quot;</p><ul><li><strong>Radio examples</strong>: Radiomaster <a href="https://rcsearch.ru/?s=radiomaster+pocket" target="_blank" rel="noreferrer">Pocket</a>, <a href="https://rcsearch.ru/?s=radiomaster+tx12" target="_blank" rel="noreferrer">TX12</a>, <a href="https://rcsearch.ru/?s=radiomaster+zorro" target="_blank" rel="noreferrer">Zorro</a>, <a href="https://rcsearch.ru/?s=radiomaster+boxer" target="_blank" rel="noreferrer">Boxer</a>.</li></ul><h2 id="most-budget-friendly-set-for-indoor-calm-weather-flying-250-350" tabindex="-1">Most Budget-Friendly Set for Indoor/Calm Weather Flying ($250-350) <a class="header-anchor" href="#most-budget-friendly-set-for-indoor-calm-weather-flying-250-350" aria-label="Permalink to &quot;Most Budget-Friendly Set for Indoor/Calm Weather Flying ($250-350)&quot;">​</a></h2><p>This is a better option than a Cetus because you can continue to use this equipment as you grow. This price range strictly covers analog video with a basic headset. A &quot;Tiny Whoop&quot; is the best drone choice here. Avoid &quot;no-name&quot; manufacturers with questionable quality; the risk is entirely yours.</p><ul><li><strong>Radios under $100</strong>: Radiomaster <a href="https://rcsearch.ru/?s=radiomaster+pocket" target="_blank" rel="noreferrer">Pocket</a>, <a href="https://rcsearch.ru/?s=radiomaster+tx12" target="_blank" rel="noreferrer">TX12</a>, <a href="https://rcsearch.ru/?s=radiomaster+zorro" target="_blank" rel="noreferrer">Zorro</a>; Jumper <a href="https://rcsearch.ru/?s=jumper+t-pro" target="_blank" rel="noreferrer">T-pro</a>, <a href="https://rcsearch.ru/?s=jumper+t20" target="_blank" rel="noreferrer">T20</a>. <a href="https://propwashservice.com/en/intro/tx" target="_blank" rel="noreferrer">ELRS 2.4GHz</a> version is recommended. Don&#39;t forget batteries!</li><li><strong>Analog Goggles under $100</strong>: Eachine <a href="https://rcsearch.ru/-c1814" target="_blank" rel="noreferrer">EV800D</a>, <a href="https://rcsearch.ru/-c7798" target="_blank" rel="noreferrer">EV800DM</a>.</li><li><strong>Tiny Whoops under $100</strong>: <a href="https://rcsearch.ru/-c29293" target="_blank" rel="noreferrer">Mobula6</a>, <a href="https://rcsearch.ru/-c33913" target="_blank" rel="noreferrer">Mobula7</a>, <a href="https://rcsearch.ru/-c35745" target="_blank" rel="noreferrer">Mobeetle6</a>. Ensure the radio protocol matches your radio (e.g., ELRS).</li><li><strong>Charger + (if needed) Power Supply</strong>: <a href="https://rcsearch.ru/-c46257" target="_blank" rel="noreferrer">VIFLY WhoopStor</a>.</li><li><strong>Batteries</strong>: GNB/Tattu according to whoop specs. For 65mm, 1S 300-380mAh; for 75mm, 1S or 2S 450-550mAh. Note: Whoops often use internal PH2.0 connectors. If possible, switch to BT2.0/A30 connectors for better performance. The suggested charger supports both.</li><li><strong>Consumables</strong>: Spare propellers matching your motor shaft diameter.</li></ul><h2 id="budget-outdoor-starter-set-400-500" tabindex="-1">Budget Outdoor Starter Set ($400-500) <a class="header-anchor" href="#budget-outdoor-starter-set-400-500" aria-label="Permalink to &quot;Budget Outdoor Starter Set ($400-500)&quot;">​</a></h2><p>Still an analog video system.</p><ul><li><strong>Radios under $150</strong>: Radiomaster <a href="https://rcsearch.ru/?s=radiomaster+pocket" target="_blank" rel="noreferrer">Pocket</a>, <a href="https://rcsearch.ru/?s=radiomaster+tx12" target="_blank" rel="noreferrer">TX12</a>, <a href="https://rcsearch.ru/?s=radiomaster+zorro" target="_blank" rel="noreferrer">Zorro</a>, <a href="https://rcsearch.ru/?s=radiomaster+boxer" target="_blank" rel="noreferrer">Boxer</a>; Jumper <a href="https://rcsearch.ru/?s=jumper+t-pro" target="_blank" rel="noreferrer">T-pro</a>, <a href="https://rcsearch.ru/?s=jumper+t20" target="_blank" rel="noreferrer">T20</a>. ELRS 2.4GHz recommended.</li><li><strong>Analog Goggles under $100</strong>: Eachine <a href="https://rcsearch.ru/-c1814" target="_blank" rel="noreferrer">EV800D</a>, <a href="https://rcsearch.ru/-c7798" target="_blank" rel="noreferrer">EV800DM</a>.</li><li><strong>Drones under $200</strong>: <a href="https://rcsearch.ru/-c46627" target="_blank" rel="noreferrer">HGLRC Drashark</a>, <a href="https://rcsearch.ru/-c46027" target="_blank" rel="noreferrer">Happymodel Mobula8</a>, <a href="https://rcsearch.ru/-c30667" target="_blank" rel="noreferrer">Crux3</a>, <a href="https://rcsearch.ru/-c45326" target="_blank" rel="noreferrer">Crux35</a>, <a href="https://rcsearch.ru/-c35553" target="_blank" rel="noreferrer">iFlight Baby Nazgul Nano</a>, <a href="https://rcsearch.ru/-c27390" target="_blank" rel="noreferrer">GEPRC Smart Phantom 2.5&quot;</a>. Ensure analog video and matching radio protocol.</li><li><strong>Charger + (if needed) Power Supply</strong>: For 1S: <a href="https://rcsearch.ru/-c46257" target="_blank" rel="noreferrer">WhoopStor</a>. For 2S+: <a href="https://rcsearch.ru/-c47308" target="_blank" rel="noreferrer">SkyRC B6 Neo</a>, ToolkitRC <a href="https://rcsearch.ru/-c6063" target="_blank" rel="noreferrer">M6</a>, <a href="https://rcsearch.ru/-c25346" target="_blank" rel="noreferrer">M7</a>, <a href="https://rcsearch.ru/?s=toolkit+m6d" target="_blank" rel="noreferrer">M6D (Dual Port)</a>, <a href="https://rcsearch.ru/-c39020" target="_blank" rel="noreferrer">M7AC (Built-in PSU)</a>, <a href="https://rcsearch.ru/-c8911" target="_blank" rel="noreferrer">iSDT 608AC</a>. Check connector types (e.g., XT60/XT30).</li><li><strong>Batteries</strong>: CNHL/GNB/Tattu. Start with at least 3-5 packs.</li><li><strong>Consumables</strong>: Spare propellers, battery straps.</li></ul><h2 id="comfortable-budget-entry-550-800" tabindex="-1">Comfortable Budget Entry ($550-800) <a class="header-anchor" href="#comfortable-budget-entry-550-800" aria-label="Permalink to &quot;Comfortable Budget Entry ($550-800)&quot;">​</a></h2><p>Still an analog video system.</p><ul><li><strong>Radios under $150</strong>: Radiomaster <a href="https://rcsearch.ru/?s=radiomaster+pocket" target="_blank" rel="noreferrer">Pocket</a>, <a href="https://rcsearch.ru/?s=radiomaster+tx12" target="_blank" rel="noreferrer">TX12</a>, <a href="https://rcsearch.ru/?s=radiomaster+zorro" target="_blank" rel="noreferrer">Zorro</a>, <a href="https://rcsearch.ru/?s=radiomaster+boxer" target="_blank" rel="noreferrer">Boxer</a>. ELRS 2.4GHz recommended.</li><li><strong>Analog Goggles under $300</strong>: Eachine <a href="https://rcsearch.ru/-c2397" target="_blank" rel="noreferrer">EV200D</a>, <a href="https://rcsearch.ru/-c10462" target="_blank" rel="noreferrer">EV300D</a>; <a href="https://rcsearch.ru/?s=Skyzone+SKY02" target="_blank" rel="noreferrer">Skyzone SKY02</a> (S, V, C, X versions are similar; OLED screens on X), <a href="https://rcsearch.ru/-c20692" target="_blank" rel="noreferrer">Cobra X</a>. Check second-hand markets for deals.</li><li><strong>Drones under $250</strong>: Sets up to 3.5&quot; (e.g., <a href="https://rcsearch.ru/-c27048" target="_blank" rel="noreferrer">GEPRC Smart 35</a>) or 5&quot; racers like <a href="https://rcsearch.ru/-c45174" target="_blank" rel="noreferrer">iFlight Nazgul5</a> or <a href="https://rcsearch.ru/-c36404" target="_blank" rel="noreferrer">Titan XL5</a>. Note: 6S batteries are more powerful but more expensive.</li><li><strong>Charger + (if needed) PSU</strong>: <a href="https://rcsearch.ru/-c47308" target="_blank" rel="noreferrer">SkyRC B6 Neo</a>, ToolkitRC <a href="https://rcsearch.ru/?s=toolkit+m6d" target="_blank" rel="noreferrer">M6D</a>, <a href="https://rcsearch.ru/-c39020" target="_blank" rel="noreferrer">M7AC</a>.</li><li><strong>Batteries</strong>: CNHL/GNB/Tattu. Start with at least 3-5 packs.</li><li><strong>Consumables</strong>: Spare propellers, battery straps.</li><li><a href="https://propwashservice.com/en/shop/nessesary" target="_blank" rel="noreferrer">Tools like Hex drivers and nut wrenches</a>.</li></ul><h2 id="comfortable-entry-800-1500" tabindex="-1">Comfortable Entry ($800-1500) <a class="header-anchor" href="#comfortable-entry-800-1500" aria-label="Permalink to &quot;Comfortable Entry ($800-1500)&quot;">​</a></h2><p>Congratulations, you can now choose a video system to your liking!</p><ul><li><a href="https://propwashservice.com/en/intro/tx" target="_blank" rel="noreferrer">Radio examples. Don&#39;t forget batteries!</a></li><li><a href="https://propwashservice.com/en/intro/vrx" target="_blank" rel="noreferrer">Goggles and video systems for your needs</a></li><li><a href="https://propwashservice.com/en/intro/flightstyles" target="_blank" rel="noreferrer">Drone styles and radio link compatibility</a></li><li><a href="https://propwashservice.com/en/intro/power#how-to-choose-a-charger" target="_blank" rel="noreferrer">Chargers and power supplies</a></li><li><strong>Batteries</strong>: CNHL/GNB/Tattu/Dogcom. Start with at least 3-5 packs.</li><li><strong>Consumables</strong>: Spare propellers, battery straps, and spare parts like arms, motors, or a backup camera if you plan to fly hard.</li><li><a href="https://propwashservice.com/en/shop/nessesary" target="_blank" rel="noreferrer">Tools like Hex drivers and nut wrenches</a>.</li></ul>',47)])])}const b=t(n,[["render",i]]);export{g as __pageData,b as default};
